import { z } from "zod";
import { getOrderlyEnvConfig } from "@/utils/environment";
import { readStoredAdminApiKey } from "@/utils/adminKeyAuth";
import { toast } from "@/utils/toast";
import { walletGetItem } from "./storage";

type HttpMethod = "GET" | "POST" | "PUT" | "PATCH" | "DELETE";

export interface ApiEnvelope<T> {
  success?: boolean;
  data?: T;
  rows?: T;
  message?: string;
  [key: string]: unknown;
}

interface ApiClientOptions {
  endpoint: string;
  method?: HttpMethod;
  body?: unknown;
  token?: string | null;
  headers?: HeadersInit;
  baseUrl?: string;
  useJsonBody?: boolean;
  showToastOnError?: boolean;
}

export function buildQueryString(params?: Record<string, unknown>): string {
  if (!params) return "";

  const search = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value === undefined || value === null || value === "") return;
    if (Array.isArray(value)) {
      value.forEach(entry => {
        if (entry !== undefined && entry !== null && entry !== "")
          search.append(key, String(entry));
      });
      return;
    }
    search.set(key, String(value));
  });

  const qs = search.toString();
  return qs ? `?${qs}` : "";
}

export function getStoredApiToken(): string | null {
  const stored = readStoredAdminApiKey();
  return stored?.token || stored?.key || null;
}

function sleep(ms: number) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function shouldRetryRequest(method: HttpMethod, status: number) {
  return (
    (method === "GET" || method === "PUT") &&
    [429, 502, 503, 504].includes(status)
  );
}

function extractErrorMessage(data: unknown, status: number): string {
  if (data && typeof data === "object") {
    const obj = data as Record<string, unknown>;
    if (typeof obj.message === "string") return obj.message;
    if (Array.isArray(obj.issues) && obj.issues.length > 0) {
      const joined = obj.issues
        .map(issue =>
          issue && typeof issue === "object" && "message" in issue
            ? String((issue as { message: unknown }).message)
            : ""
        )
        .filter(Boolean)
        .join("; ");
      if (joined) return joined;
    }
    if (typeof obj.error === "string") return obj.error;
    const flattened = Object.values(obj).flat().map(String).join("; ");
    if (flattened) return flattened;
  }
  if (typeof data === "string" && data.trim()) return data;
  return `Request failed with ${status}`;
}

export async function orderlyApi<T>(
  opts: ApiClientOptions & { schema: z.ZodType<T> }
): Promise<T>;
export async function orderlyApi<T>(opts: ApiClientOptions): Promise<T>;
export async function orderlyApi<T>({
  endpoint,
  method = "GET",
  body,
  token = getStoredApiToken(),
  headers,
  baseUrl = getOrderlyEnvConfig().apiBaseUrl,
  useJsonBody = true,
  showToastOnError = false,
  schema,
}: ApiClientOptions & { schema?: z.ZodType<T> }): Promise<T> {
  const url = endpoint.startsWith("http")
    ? endpoint
    : `${baseUrl}${endpoint.startsWith("/") ? endpoint : `/${endpoint}`}`;
  const requestHeaders: Record<string, string> = {
    Accept: "application/json",
  };

  if (headers) {
    new Headers(headers).forEach((value, key) => {
      requestHeaders[key] = value;
    });
  }

  if (body !== undefined && useJsonBody) {
    requestHeaders["Content-Type"] = "application/json";
  }
  if (token) {
    requestHeaders.Authorization = `Bearer ${token}`;
  }

  for (let attempt = 0; attempt < 3; attempt += 1) {
    const response = await fetch(url, {
      method,
      headers: requestHeaders,
      body:
        body !== undefined && method !== "GET"
          ? useJsonBody
            ? JSON.stringify(body)
            : (body as BodyInit)
          : undefined,
    });

    const contentType = response.headers.get("content-type") || "";
    const data = contentType.includes("application/json")
      ? await response.json()
      : await response.text();

    if (response.ok) {
      if (schema) return schema.parse(data) as T;
      return data as T;
    }

    if (attempt < 2 && shouldRetryRequest(method, response.status)) {
      await sleep(300 * 2 ** attempt);
      continue;
    }

    if (response.status === 401 && token) {
      if (typeof window !== "undefined") {
        window.dispatchEvent(new CustomEvent("authTokenExpired"));
      }
    }

    const message = extractErrorMessage(data, response.status);

    if (showToastOnError) {
      toast.error(`Request failed: ${message}`);
    }

    const error = new Error(message);
    (error as Error & { status?: number; data?: unknown }).status =
      response.status;
    (error as Error & { status?: number; data?: unknown }).data = data;
    throw error;
  }

  throw new Error("Request failed after retries.");
}

export function unwrapRows<T>(payload: unknown): T[] {
  if (Array.isArray(payload)) return payload as T[];
  const envelope = payload as ApiEnvelope<unknown> | null;
  if (Array.isArray(envelope?.rows)) return envelope.rows as T[];
  if (Array.isArray(envelope?.data)) return envelope.data as T[];
  if (
    envelope?.data &&
    typeof envelope.data === "object" &&
    Array.isArray((envelope.data as { rows?: unknown }).rows)
  ) {
    return (envelope.data as { rows: T[] }).rows;
  }
  return [];
}

export const apiClient = orderlyApi;

export function post<T = unknown>(
  endpoint: string,
  body: unknown,
  token?: string | null,
  options: Partial<ApiClientOptions> = {}
) {
  return apiClient<T>({
    endpoint,
    method: "POST",
    body,
    token: token ?? walletGetItem("auth_token"),
    ...options,
  });
}
