import { toast as odsToast } from "@/hooks/use-toast";

export const toast = {
  success: (message: string) => odsToast({ title: message, status: "success" }),
  error: (message: string) => odsToast({ title: message, status: "error" }),
  info: (message: string) => odsToast({ title: message, status: "info" }),
  warning: (message: string) => odsToast({ title: message, status: "warning" }),
};
